import org.springframework.stereotype.Service;
import java.util.*;
import java.util.concurrent.ConcurrentLinkedQueue;

@Service
public class SwiggyFallbackStrategies {

    // 1. STATIC DEFAULT — always reliable:
    private int deliveryFallback(String orderId, Exception e) {
        return 45;  // safe, never fails, user sees reasonable estimate
    }

    // 2. CACHED — last known good:
    private List<String> restaurantFallback(String city, Exception e) {
        List<String> cached = redisCache.getOrDefault("restaurants:" + city, List.of());
        System.out.println("[Fallback] Returning " + cached.size() + " cached restaurants");
        return cached;
    }

    // 3. DEGRADED MODE — less features but functional:
    private String seatMapFallback(String eventId, Exception e) {
        System.out.println("[Fallback] Interactive map unavailable — returning zone pricing");
        return "ZONE_PRICING:{orchestra:500,balcony:300}";
    }

    // 4. FAIL FAST — payment is critical, don't silently degrade:
    private java.util.concurrent.CompletableFuture<String> paymentFallback(
            String orderId, Exception e) {
        System.err.println("[CRITICAL] Payment service unavailable for " + orderId);
        throw new RuntimeException("Payment service unavailable — please retry", e);
    }

    // 5. QUEUE FOR RETRY — eventual delivery:
    private void smsFallback(String userId, String message, Exception e) {
        retryQueue.offer(userId + "|" + message);
        System.out.println("[Fallback] SMS queued for retry: " + userId);
    }

    private Map<String, List<String>> redisCache = new HashMap<>();
    private ConcurrentLinkedQueue<String> retryQueue = new ConcurrentLinkedQueue<>();
}

import org.springframework.context.annotation.*;
import org.springframework.web.client.RestTemplate;
import org.springframework.http.client.SimpleClientHttpRequestFactory;

@Configuration
public class HttpConfig {

    @Bean("bankVerificationRestTemplate")
    public RestTemplate bankVerificationRestTemplate() {
        var factory = new SimpleClientHttpRequestFactory();
        factory.setConnectTimeout(2000);  // 2s: fail if server unreachable
        factory.setReadTimeout(5000);     // 5s: fail if server doesn't respond
        return new RestTemplate(factory);
    }

    // WHY BOTH?
    // HTTP connect timeout (2s):
    //   Fires when TCP connection cannot be established
    //   Network outage, wrong host, firewall
    //   Prevents blocking on unreachable host
    //
    // HTTP read timeout (5s):
    //   Fires when connected but server takes too long to respond
    //   Server overloaded, processing too long, partial response
    //   Prevents indefinite wait after connection
    //
    // @TimeLimiter (3s at application level):
    //   Application-level budget; catches any overhead beyond HTTP timeouts
    //   Feeds into CircuitBreaker failure tracking
    //   Cancels the CompletableFuture if still running
    //
    // Order of protection:
    //   T=0: call starts
    //   T=2s: connect timeout fires (if no TCP connection)
    //   T=5s: read timeout fires (if connected but no response)
    //   T=3s: @TimeLimiter fires (application level — may fire before read timeout)
}

