class TimeLimiterTest {
    @Autowired FlipkartRecommendationService svc;
    @MockBean FlipkartRecommendationService.RecEngine engine;
    @Autowired io.github.resilience4j.circuitbreaker.CircuitBreakerRegistry reg;

    @BeforeEach void reset() { reg.circuitBreaker("recs").reset(); }

    @Test
    void timeout_triggers_fallback() throws Exception {
        // Engine takes 3 seconds — timeout is 2 seconds:
        when(engine.forUser(anyString())).thenAnswer(inv -> {
            Thread.sleep(3000);
            return List.of("slow result");
