import io.github.resilience4j.circuitbreaker.annotation.CircuitBreaker;
import org.springframework.stereotype.Service;
import java.util.*;
import java.util.concurrent.*;

@Service
public class ZerodhaMarketDataService {
    private final MarketDataClient client;
    private final ConcurrentHashMap<String, Double> priceCache = new ConcurrentHashMap<>();

    ZerodhaMarketDataService(MarketDataClient c) { client = c; }

    @TimeLimiter(name = "market-ltp", fallbackMethod = "cachedLTP")
    @CircuitBreaker(name = "market-ltp")
    public CompletableFuture<Double> getLTP(String symbol) {
        return CompletableFuture.supplyAsync(() -> {
            Double price = client.getLastTradedPrice(symbol);
            priceCache.put(symbol, price);  // update cache on success
            return price;
        });
    }

    private CompletableFuture<Double> cachedLTP(String symbol, Exception e) {
        Double cached = priceCache.get(symbol);
        if (cached != null) {
            System.out.printf("[Fallback] Stale price for %s: %.2f%n", symbol, cached);
            return CompletableFuture.completedFuture(cached);
        }
        System.out.println("[Fallback] No cached price for " + symbol);
        return CompletableFuture.completedFuture(0.0);  // unknown price
    }

    interface MarketDataClient { Double getLastTradedPrice(String sym); }
}

