@Service
public class MultiTimeoutService {

    // CRITICAL: 5s timeout, fail fast fallback:
    @TimeLimiter(name = "payments", fallbackMethod = "paymentTimeout")
    @CircuitBreaker(name = "payments")
    public CompletableFuture<String> processPayment(String orderId) {
        return CompletableFuture.supplyAsync(() -> paymentClient.charge(orderId));
    }
    private CompletableFuture<String> paymentTimeout(String id, Exception e) {
        throw new RuntimeException("Payment timed out — please retry", e);
    }

    // NON-CRITICAL: 1.5s timeout, quick cached fallback:
    @TimeLimiter(name = "recommendations", fallbackMethod = "quickFallback")
    @CircuitBreaker(name = "recommendations")
    public CompletableFuture<List<String>> getRecommendations(String uid) {
        return CompletableFuture.supplyAsync(() -> recClient.forUser(uid));
    }
    private CompletableFuture<List<String>> quickFallback(String uid, Exception e) {
        return CompletableFuture.completedFuture(List.of("iPhone 15", "Galaxy S24"));
    }

    // BATCH: 30s timeout, partial result fallback:
    @TimeLimiter(name = "reports", fallbackMethod = "partialReport")
    public CompletableFuture<String> generateReport(String type) {
        return CompletableFuture.supplyAsync(() -> reportEngine.generate(type));
    }
    private CompletableFuture<String> partialReport(String type, Exception e) {
        return CompletableFuture.completedFuture("PARTIAL:" + type + ":timeout");
    }

    interface PaymentClient { String charge(String id); }
    interface RecClient { List<String> forUser(String uid); }
    interface ReportEngine { String generate(String type); }
    PaymentClient paymentClient = id -> id;
    RecClient recClient = uid -> List.of();
    ReportEngine reportEngine = type -> type;
}

