@Service
class ZerodhaResilienceService {
    interface PriceClient    { double getPrice(String sym); }
    interface OrderClient    { String submitOrder(String id); }
    interface ReportClient   { String getReport(String type); }
    interface AlertClient    { void sendAlert(String msg); }

    private final PriceClient pc; private final OrderClient oc;
    private final ReportClient rc; private final AlertClient ac;
    private final Map<String,Double> priceCache=new ConcurrentHashMap<>();
    private final Queue<String> alertQueue=new ConcurrentLinkedQueue<>();

    ZerodhaResilienceService(PriceClient p,OrderClient o,ReportClient r,AlertClient a){
        pc=p;oc=o;rc=r;ac=a;
    }

    // Strategy 1: cached data
    @CircuitBreaker(name="z-price",fallbackMethod="cachedPrice")
    public double getLTP(String sym){
        double p=pc.getPrice(sym); priceCache.put(sym,p); return p;
    }
    private double cachedPrice(String sym,Exception e){
        return priceCache.getOrDefault(sym,-1.0);
    }

    // Strategy 2: fail fast (orders are critical)
    @CircuitBreaker(name="z-order",fallbackMethod="orderFailed")
    public String submitOrder(String id){ return oc.submitOrder(id); }
    private String orderFailed(String id,Exception e){
        throw new RuntimeException("Order submission unavailable",e);
    }

    // Strategy 3: static default
    @CircuitBreaker(name="z-report",fallbackMethod="defaultReport")
    public String getReport(String type){ return rc.getReport(type); }
    private String defaultReport(String type,Exception e){
        return "Report temporarily unavailable — try again later";
    }

    // Strategy 4: queue for retry
    @CircuitBreaker(name="z-alert",fallbackMethod="queueAlert")
    public void sendAlert(String msg){ ac.sendAlert(msg); }
    private void queueAlert(String msg,Exception e){
        alertQueue.offer(msg);
    }

    Queue<String> getAlertQueue(){return alertQueue;}
}

@SpringBootTest
class ZResilienceServiceTest{
    @Autowired ZerodhaResilienceService svc;
    @MockBean ZerodhaResilienceService.PriceClient pc;
    @MockBean ZerodhaResilienceService.OrderClient oc;
    @MockBean ZerodhaResilienceService.ReportClient rc;
    @MockBean ZerodhaResilienceService.AlertClient ac;
    @Autowired CircuitBreakerRegistry reg;
    @BeforeEach void reset(){
        for(String n:List.of("z-price","z-order","z-report","z-alert"))
            try{reg.circuitBreaker(n).reset();}catch(Exception ignore){}
        svc.getAlertQueue().clear();
    }
    @Test void cachedPrice_returnedOnFailure(){
        when(pc.getPrice("TCS")).thenReturn(3890.0);
        svc.getLTP("TCS");  // populate cache
        when(pc.getPrice("TCS")).thenThrow(new RuntimeException("down"));
        assertEquals(3890.0,svc.getLTP("TCS"),0.01);
    }
    @Test void alert_queued_onFailure(){
        doThrow(new RuntimeException("alert down")).when(ac).sendAlert(any());
        svc.sendAlert("CIRCUIT BREAKER OPENED");
        assertFalse(svc.getAlertQueue().isEmpty());
    }
}

