import io.github.resilience4j.timelimiter.annotation.TimeLimiter;
import io.github.resilience4j.circuitbreaker.annotation.CircuitBreaker;
import org.springframework.stereotype.Service;
import java.util.concurrent.CompletableFuture;
import java.util.*;

@Service
public class FlipkartProductLoader {
    private final SlowServiceA svcA;
    private final SlowServiceB svcB;
    private final SlowServiceC svcC;
    FlipkartProductLoader(SlowServiceA a,SlowServiceB b,SlowServiceC c){svcA=a;svcB=b;svcC=c;}

    @TimeLimiter(name="svc-a",fallbackMethod="defaultA")
    @CircuitBreaker(name="svc-a")
    public CompletableFuture<String> callA(String id){return CompletableFuture.supplyAsync(()->svcA.call(id));}
    private CompletableFuture<String> defaultA(String id,Exception e){return CompletableFuture.completedFuture("A_DEFAULT");}

    @TimeLimiter(name="svc-b",fallbackMethod="defaultB")
    @CircuitBreaker(name="svc-b")
    public CompletableFuture<String> callB(String id){return CompletableFuture.supplyAsync(()->svcB.call(id));}
    private CompletableFuture<String> defaultB(String id,Exception e){return CompletableFuture.completedFuture("B_DEFAULT");}

    @TimeLimiter(name="svc-c",fallbackMethod="defaultC")
    @CircuitBreaker(name="svc-c")
    public CompletableFuture<String> callC(String id){return CompletableFuture.supplyAsync(()->svcC.call(id));}
    private CompletableFuture<String> defaultC(String id,Exception e){return CompletableFuture.completedFuture("C_DEFAULT");}

    // Load all 3 IN PARALLEL:
    public Map<String,String> loadProduct(String productId) throws Exception {
        var fa = callA(productId);  // starts immediately
        var fb = callB(productId);  // starts immediately
        var fc = callC(productId);  // starts immediately
        // All 3 running in parallel:
        CompletableFuture.allOf(fa,fb,fc).get(4,java.util.concurrent.TimeUnit.SECONDS);
        return Map.of("a",fa.get(), "b",fb.get(), "c",fc.get());
        // Total time: max(A_time, B_time, C_time) — NOT A+B+C!
    }

    interface SlowServiceA { String call(String id); }
    interface SlowServiceB { String call(String id); }
    interface SlowServiceC { String call(String id); }

    public static void main(String[] a){
        System.out.println("Sequential: svc_A(1s) + svc_B(1s) + svc_C(1s) = 3 seconds");
        System.out.println("Parallel:   max(1s, 1s, 1s) = 1 second total");
    }
}

import io.github.resilience4j.timelimiter.annotation.TimeLimiter;
import io.github.resilience4j.circuitbreaker.annotation.*;
import io.github.resilience4j.circuitbreaker.*;
import org.springframework.stereotype.*;
import java.util.concurrent.*;
import java.util.*;
import java.util.concurrent.atomic.AtomicInteger;
import jakarta.annotation.PostConstruct;
import org.springframework.boot.test.context.SpringBootTest;
