@Service
class FKProductPage{
    interface DetailsApi{Map<String,Object> get(String id);}
    interface ReviewsApi{List<String> get(String id);}
    interface RelatedApi{List<String> get(String id);}
    private final DetailsApi da;private final ReviewsApi ra;private final RelatedApi rel;
    FKProductPage(DetailsApi d,ReviewsApi r,RelatedApi re){da=d;ra=r;rel=re;}
    @TimeLimiter(name="fk-details",fallbackMethod="detFb") @CircuitBreaker(name="fk-details")
    public CompletableFuture<Map<String,Object>> details(String id){return CompletableFuture.supplyAsync(()->da.get(id));}
    private CompletableFuture<Map<String,Object>> detFb(String id,Exception e){return CompletableFuture.completedFuture(Map.of("id",id,"name","Loading..."));}
    @TimeLimiter(name="fk-reviews2",fallbackMethod="revFb") @CircuitBreaker(name="fk-reviews2")
    public CompletableFuture<List<String>> reviews(String id){return CompletableFuture.supplyAsync(()->ra.get(id));}
    private CompletableFuture<List<String>> revFb(String id,Exception e){return CompletableFuture.completedFuture(List.of());}
    @TimeLimiter(name="fk-related2",fallbackMethod="relFb") @CircuitBreaker(name="fk-related2")
    public CompletableFuture<List<String>> related(String id){return CompletableFuture.supplyAsync(()->rel.get(id));}
    private CompletableFuture<List<String>> relFb(String id,Exception e){return CompletableFuture.completedFuture(List.of("Top Pick"));}
    public Map<String,Object> loadPage(String id) throws Exception{
        var fd=details(id);var fr=reviews(id);var frel=related(id);
        CompletableFuture.allOf(fd,fr,frel).get(5,TimeUnit.SECONDS);
        return Map.of("details",fd.get(),"reviews",fr.get(),"related",frel.get());
    }
}

@Service
class FKTimeoutMonitor{
    public final AtomicInteger timeouts=new AtomicInteger(0);
    private final CircuitBreakerRegistry reg;
    FKTimeoutMonitor(CircuitBreakerRegistry r){reg=r;}
    @PostConstruct void listen(){
        reg.getAllCircuitBreakers().forEach(cb->cb.getEventPublisher()
            .onError(e->{if(e.getThrowable() instanceof java.util.concurrent.TimeoutException) timeouts.incrementAndGet();}));
    }
}

@SpringBootTest
class FKProductPageTest{
    @Autowired FKProductPage pg;
    @Autowired FKTimeoutMonitor mon;
    @MockBean FKProductPage.DetailsApi da;
    @MockBean FKProductPage.ReviewsApi ra;
    @MockBean FKProductPage.RelatedApi rel;
    @Autowired CircuitBreakerRegistry reg;
    @BeforeEach void reset(){
        for(String n:List.of("fk-details","fk-reviews2","fk-related2"))
            try{reg.circuitBreaker(n).reset();}catch(Exception ignore){}
        mon.timeouts.set(0);
    }
    @Test void pageLoads_allServicesUp() throws Exception{
        when(da.get(any())).thenReturn(Map.of("name","iPhone 15"));
        when(ra.get(any())).thenReturn(List.of("Great product!"));
        when(rel.get(any())).thenReturn(List.of("Galaxy S24"));
        var page=pg.loadPage("P001");
        assertNotNull(page.get("details"));
    }
    @Test void details_fallback_pageStillLoads() throws Exception{
        when(da.get(any())).thenThrow(new RuntimeException("down"));
        when(ra.get(any())).thenReturn(List.of());
        when(rel.get(any())).thenReturn(List.of());
        var page=pg.loadPage("P001");
        Map<?,?> det=(Map<?,?>)page.get("details");
        assertEquals("Loading...",det.get("name"));
    }
    @Test void related_fallback_returnsTopPick() throws Exception{
        when(da.get(any())).thenReturn(Map.of("name","Test"));
        when(ra.get(any())).thenReturn(List.of());
        when(rel.get(any())).thenThrow(new RuntimeException("down"));
        var page=pg.loadPage("P001");
        @SuppressWarnings("unchecked")
        List<String> related=(List<String>)page.get("related");
        assertTrue(related.contains("Top Pick"));
    }
}
